script.inlineScript:
import { writeFileSync } from 'fs';

const options = [
  { label: 'Weekly Report', description: 'Standard weekly status report', value: { templateId: 'weekly', sections: ['summary', 'metrics', 'risks'] } },
  { label: 'Incident Report', description: 'Post-incident analysis template', value: { templateId: 'incident', sections: ['timeline', 'impact', 'root-cause', 'actions'] } },
  { label: 'Audit Trail', description: 'Compliance audit documentation', value: { templateId: 'audit', sections: ['scope', 'findings', 'evidence', 'recommendations'] } }
];

writeFileSync('/output/result.json', JSON.stringify({ options, summary: `Found ${options.length} templates` }));

import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const selected = input.steps?.['pick-template'];
const templateId = selected?.templateId || 'unknown';
const sections = selected?.sections || [];

const doc = sections.map(s => `## ${s.charAt(0).toUpperCase() + s.slice(1)}\n\n[To be filled]`).join('\n\n');

writeFileSync('/output/result.json', JSON.stringify({
  templateId,
  document: doc,
  summary: `Generated ${templateId} with ${sections.length} sections`
}));
